public static int lis(int[] arr) {
    Map<Integer,Integer> ends = new HashMap<Integer, Integer>(100);
    int longest = 0;
    int i = 0;
    for (int val : arr) {
        if (val < arr[ends.get(longest)]) {
            ends.put(longest+1, i);
            longest++;
        } else {
            int index = Collections.binarySearch(Arrays.asList(ends.keySet().toArray(new Integer[0])), longest, Collections.reverseOrder());
            ends.put(index < 0 ? ~index : index, i);
